package com.hospital.management.controller;
import com.hospital.management.dao.AuditLogDao;import com.hospital.management.dao.impl.AuditLogDaoImpl;import com.hospital.management.model.AuthenticatedUser;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/logout") public class LogoutServlet extends HttpServlet {private final AuditLogDao audit;public LogoutServlet(){this(new AuditLogDaoImpl());}public LogoutServlet(AuditLogDao audit){this.audit=audit;}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{HttpSession s=q.getSession(false);if(s!=null){Object v=s.getAttribute("authenticatedUser");if(v instanceof AuthenticatedUser u)audit.recordEvent("LOGOUT",u.getUserId(),"USER",u.getUserId(),q.getRemoteAddr(),q.getHeader("User-Agent"));s.invalidate();}r.sendRedirect(q.getContextPath()+"/login?logout=success");}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendRedirect(q.getContextPath()+"/login");}}
